var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. AS003M0008-07: <color=#ffd34c>【기록-001】 검토 회의</color>","JPN":"AEGIS 8 PBLIT SECURITY SEQUENCE：<color=#ffd34c>ACTIVATED</color>……\\nADC FACTOR：<color=#ffd34c>ALPHA CONFIRMED</color>……\\nCCN No. AS003M0008-07：<color=#ffd34c>【記録-001】 検討会議</color>","ENG":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. AS003M0008-07: <color=#ffd34c>【Record-001】 Review Conference</color>","TWN":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. AS003M0008-07: <color=#ffd34c>【記錄-001】 討論會議</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"하아......","JPN":"はあ……","ENG":"*Sigh*","TWN":"唉……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"만나자마자 한숨부터 쉬다니, 업무 강도 때문인가?","JPN":"いきなりため息とは。そんなに仕事がきついのかね？","ENG":"Why are you sighing? Is it because of the workload?","TWN":"一見面就嘆氣，是因為工作量太大了嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"어떤 분께서 정보부가 해야 될 일을 저 한 사람에게 모조리 일임하시긴 했죠.","JPN":"あるお方が、本来なら情報部向きの仕事を私に丸ごと一任してくれたのは確かです。","ENG":"Someone dumped all the intelligence work on me.","TWN":"某人把情報部的工作全交給了我。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"그런데 정작 일을 맡기신 분은 직원들과 놀러 다니느라 바쁘시고......","JPN":"なのにその方ときたら、仕事を押し付けておきながら社員たちと忙しそうに遊びまわっていまして……","ENG":"And that certain someone has been busy having fun with the employees...","TWN":"但是交代我工作的負責人，卻忙著和員工們玩樂……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"크흠. 흠. 그건 놀러 다니는 게 아니라 잠행일세, 잠행.","JPN":"オッ、オッホン。遊んでいるのではないぞ。あれもれっきとしたスニーキング・​ミッション、潜入任務の類なのだ。","ENG":"Ahem. Ahem. I wasn't having fun. I was working undercover.","TWN":"咳咳，咳。那不是去玩，那是去臥底呀，臥底。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"사장이라면 직원들의 고충도 들어 주고 그래야지.","JPN":"社長たる者、社員の悩みにも耳を傾けねばならんからな。","ENG":"As the CEO, I should be aware of the problems faced by my employees.","TWN":"是老闆的話，就得去聽聽員工們的苦水啊。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"제 허리에서 나는 소리도 귀 기울여 주시죠.","JPN":"私の腰が上げる悲鳴にも、耳を傾けてほしいものです。","ENG":"Could you please be aware of my poor back as well?","TWN":"那您聽聽我的腰發出的聲音。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"......참고하겠네.","JPN":"……善処しよう。","ENG":"I'll keep that in mind.","TWN":"……我會當作參考的。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"입에 발린 말이라도 해 주셔서 감사합니다.","JPN":"建前だとしても、そう言っていただけるとありがたいですね。","ENG":"Thank you for at least pretending to care.","TWN":"儘管是句沒有誠意的客套話，能聽您這麼說真是太感謝了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"그래서...... 무슨 일이길래 세상 다 산 것처럼 그러고 있나?","JPN":"それで……、なぜため息などついていたのだね？悩みがあるなら聞こうではないか。","ENG":"So... what's bothering you?","TWN":"所以……到底是什麼事情讓妳一臉呆樣，一副快要死掉的樣子？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"사장으로서 도울 수 있는 일이라면 나도 거들어 주겠네.","JPN":"社長として助けてやれることならば、私が力になろう。","ENG":"If I can help you out as the CEO, I will do my best.","TWN":"如果是作為老闆能做到的事情，我也會幫你的。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"최근 새로 채용한 직원 때문입니다.","JPN":"最近新しく採用した社員が問題なんです。","ENG":"It's the new recruit.","TWN":"因為最近新來的員工。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"흠, 어디 봄세.","JPN":"ふむ、どれどれ。","ENG":"Hmm, let's see.","TWN":"嗯，我看看。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"알트 소대...... 아, 유진 양이로군. 그 돌격대원.","JPN":"アルト小隊……ああ、シロコ君か。あの切り込み隊員だな。","ENG":"ALT Squad... Oh, it's Eujin. That stormtrooper.","TWN":"阿爾特小隊……喔，劉珍小姐啊，那個突擊隊員。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"전투가 벌어질 때마다 다짜고짜 앞으로 튀어 나가는 점만 빼면 실적은 좋아 보이던데, 다른 문제가 있나?","JPN":"戦闘のたびに後先構わず突っ込んでいくところにさえ目を瞑れば、成果は上々だったはずだが……他にも何か問題があるのかね？","ENG":"Looks like she's doing well, except that she is always charging at the enemy as soon as the battle begins. Are there any other problems?","TWN":"除了每次戰鬥時都會胡亂向前衝以外，業績看起來很不錯啊，有其他問題嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"식비 때문입니다.","JPN":"ズバリ、食費です。","ENG":"Her food expenses.","TWN":"因為她的伙食費。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"식비?","JPN":"食費？","ENG":"Food expenses?","TWN":"伙食費？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"유진 양의 그 저돌적인 전투 방식은 동급 카운터 중에서도 우월한 신체 능력으로 뒷받침되는 겁니다.","JPN":"彼女の猪突猛進な戦い方は、同ランクのカウンターの中でも、優れた身体能力があってこそ可能になっています。","ENG":"Eujin's reckless combat style is backed by her outstanding physique, unmatched by Counters of the same grade.","TWN":"劉珍小姐那種魯莽的戰鬥方式，是建立在她在同級制裁者中，也相當優秀的身體能力。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"움직임만 보면 A급 카운터에도 견줄 정도죠.","JPN":"動きだけ見るなら、彼女はA級カウンターにも引けは取りません。","ENG":"Her movement is almost on par with those of Grade A Counters.","TWN":"只看動作的話，甚至可以和A級制裁者相比。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"문제는 남들보다 열량도 몇 배로 소모한다는 겁니다.","JPN":"問題なのは並外れた動きであるゆえに、彼女は人の何倍ものカロリーを消費するということです。","ENG":"But the problem is that she consumes several times more calories than others.","TWN":"問題是熱量消耗也是別人的好幾倍。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"아, 그런 고충이 있었군......","JPN":"ああ、そのような問題があったのか……","ENG":"Ah, that could be an issue.","TWN":"啊，原來有這樣的苦衷啊……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"뭐, 아무리 그래도 한 명이지 않나? 먹어 봐야 얼마나 한다고......","JPN":"まあしかし、いくら大食いでもたかが一人だろう？　食費がかかると言ったって……","ENG":"Well, but it's just one person. How much can she eat?","TWN":"不過，她再怎麼說也只是一個人吧？這樣是能吃多少……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"저희 회사가 그렇게 풍족한 형편이 아니라는 건 아시지 않습니까?","JPN":"わが社の懐事情が芳しくないことは、社長もご存知でしょう？","ENG":"You know that our company is not in good financial condition.","TWN":"您知道公司的情況並不富裕吧？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"적당히 넘어갈 건이었으면 김하나 부장 선에서 정리가 됐겠죠.","JPN":"何とか済ませられる額だったなら、とっくにナカシマ・スズカ部長が片付けています。","ENG":"If it wasn't a big issue, Manager Kim Hana would have taken care of it.","TWN":"如果只是適當的超出，金荷娜部長就能解決。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"그 말도 안 되는 식탐을 미리 알았더라면 알트 소대 채용도 한 번쯤 더 고민했을 겁니다.","JPN":"あの常軌を逸した食べっぷりを先に見てたなら、アルト小隊の採用を考え直したはずです。","ENG":"And if we knew about her insane appetite, we would have reconsidered hiring the ALT Squad.","TWN":"要是事先知道那個誇張的食量，我肯定會再三考慮錄用阿爾特小隊的事情。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"알트 소대 채용 건은 자네가 서윤 양에게 영혼까지 농락당한 결과......","JPN":"アルト小隊を採用した件は、君がアオイ君に魂まで弄ばれた結果なのでは……","ENG":"ALT Squad was recruited because you were completely outclassed by Seo Yoon...","TWN":"錄用阿爾特小隊這件事，完全是你被徐芸耍了的結果……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"방금 뭐라고 하셨죠?","JPN":"今何とおっしゃいました？","ENG":"What did you just say?","TWN":"您剛才說什麼？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"크흠! 크흠! 아무것도 아닐세. 그보다 하던 이야기나 계속 하도록 하지.","JPN":"ゴ、ゴホン！何も言ってないぞ。それより、話の続きを聞かせてくれ。","ENG":"Ahem! Ahem! Nothing. Let's get back to the subject at hand.","TWN":"咳！咳！沒什麼。繼續說之前的事情吧。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"제가 봤을 때 열량은 구실이고 그냥 먹성이 좋은 것 같습니다. 아니, 확실합니다.","JPN":"私が見たところ、戦闘時のカロリー消費云々はあくまで口実で、単に食欲が旺盛なだけの気がします。いえ、間違いありません。","ENG":"I think the calories are just an excuse; she just likes to eat a lot. No, I'm sure of it.","TWN":"在我看來熱量消耗只是藉口，她大概就是嘴饞。不，我肯定。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"으음, 내 상상보다 심각한가 보군.","JPN":"むう、平時でも被害は深刻というわけか。","ENG":"Hmm, that sounds more serious than I imagined.","TWN":"嗯，似乎比我想像得還要嚴重啊。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"네. 요샌 구내 식당 영양사 피해 다니느라 소화 불량에 걸릴 지경입니다.","JPN":"ええ。最近は社内食堂の栄養士から逃げ回るのが大変で、胃に穴が開きそうです。","ENG":"Exactly. I'm suffering from indigestion because I've been trying to avoid the company nutritionist.","TWN":"是的。最近為了躲著食堂裡的營養師，都到了消化不良的地步。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"갈 때마다 예산 배당하기 힘들어 죽겠다고 얼마나 눈치를 주는지......","JPN":"会うたびにどれだけ食堂の予算繰りが苦しいのかを言ってくるんです……","ENG":"Every time I go to the cafeteria, I get a handful of complaints about the budget.","TWN":"每次去的時候，分配預算都尷尬得要命，不知道被擺了多少臉色……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"이대로 가면 조만간 식당에 발도 못 붙이고 편의점에서 컵라면 끓여 먹는 처지로 전락하겠죠.","JPN":"このままだと私は食堂に近づくことすらできなくなり、コンビニのカップ麺を食べるはめになるでしょうね。","ENG":"At this rate, I won't be able to enter the cafeteria, and will end up eating cup noodles at the convenience store.","TWN":"再這樣下去，我很快就會無法踏進食堂，落到只能在便利商店吃泡麵的下場了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"게다가 그 무식 충만한...... 아니, 자폭 수준의 전투 방식으로 낭비하는 탄약 값도 만만치 않습니다.","JPN":"さらには、あの無鉄砲極まりない……半ば特攻じみた戦い方によって浪費される弾薬代も馬鹿になりません。","ENG":"In addition, Eujin's reckless, no, almost suicidal combat style always leads to a waste of ammunition.","TWN":"再加上那個有勇無謀的……不，是自爆等級的戰鬥方式，浪費的彈藥錢也不少。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"하하. 너무 마음에 두진 말게.","JPN":"ハハ、そうカリカリせずともいいだろう。","ENG":"Hah hah. Don't think too much of it.","TWN":"哈哈。不要太放在心上。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"그런 식으로 생각하면 자네도 한창 때 그 귀한 ████ 소드를 사흘에 하나씩 망가뜨리지 않았나?","JPN":"それで言えば、全盛期の君はあの貴重な██████ソードを三日に一本は壊していなかったか？","ENG":"If you put it that way, you also used to break an incredibly expensive ████ Sword once every three days.","TWN":"照你這麼說，你不是也三天就用壞一把████劍嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"메시지가 타당하면 메신저를 공격하라더니, 딱 그대로 하시네요.","JPN":"反論できないなら発言者を貶めろと言いますが、社長はまさにそのお手本ですね。","ENG":"You immediately resort to shooting the messenger.","TWN":"以子之矛，攻子之盾，您還真是會呢。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"칭찬으로 듣지.","JPN":"誉め言葉として受け取っておこう。","ENG":"I'll take that as a compliment.","TWN":"這話我就當成讚美吧。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"하지만 보급품에 드는 예산은 조금 더 챙길 수 있도록 하겠네.","JPN":"まあ何だ。補給品にかかる予算はもう少し回してもらえるようにしよう。","ENG":"But I will make sure you get a little bigger budget for the supplies.","TWN":"不過，我會多撥一些預算在補給品上的。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"회사를 위해 고생하는데 이 정도 지원은 필요할 테니까","JPN":"会社のために身を粉にしてくれてるんだからな。必要な支援は惜しまないさ。","ENG":"It's the least I can do for your hard effort.","TWN":"你為公司付出這麼多，這點程度的支援，你有需要的話我會回應你的。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"감사합니다. 앞으로는 가끔씩 엄살도 부려야겠네요.","JPN":"たまには泣き言も言ってみるものですね。これからは泣き落としも使ってみようかと思います。","ENG":"Thank you. I'll have to cry wolf from time to time.","TWN":"太感謝您了。以後我偶爾裝得可憐一點好了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"하하, 너무 남용하진 말게.","JPN":"ハハッ、お手柔らかに頼むよ。","ENG":"Hah hah, don't do it too often.","TWN":"哈哈，不要太超過就行了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};